import{_ as a,o as t,c as r,af as l}from"./chunks/framework.BSym9njW.js";const i="/hello-rocm/images/05-amd-yes/overview/amd_yes_project_overview_en.webp",p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"05-amd-yes/index.md","filePath":"en/05-amd-yes/index.md","lastUpdated":1778553795000}'),n={name:"05-amd-yes/index.md"};function o(s,e,c,h,d,m){return t(),r("div",null,[...e[0]||(e[0]=[l('<div align="center"><h1>AMD-YES 🎮</h1><strong>A Curated Collection of Cool Projects on AMD GPUs</strong></div><div align="center"><p><em>Making AI more fun, unleashing creativity</em> ✨</p><p><a href="/hello-rocm/">Back to Home</a></p></div><h2 id="🚀-quick-navigation" tabindex="-1">🚀 Quick Navigation <a class="header-anchor" href="#🚀-quick-navigation" aria-label="Permalink to &quot;🚀 Quick Navigation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Local Run (Single GPU)</th><th>Cluster Deployment (Multi-GPU)</th></tr></thead><tbody><tr><td><a href="/hello-rocm/05-amd-yes/toy-cli">🧸 toy-cli</a> ✅️</td><td><a href="/hello-rocm/05-amd-yes/happy-llm/">🚀 happy-llm</a> ✅️</td></tr><tr><td><a href="/hello-rocm/05-amd-yes/wechat-jump">🎮 WeChat Jump</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/05-amd-yes/huanhuan-chat">🎭 Chat-Huanhuan</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/05-amd-yes/hello-agents/">✈️ Smart Travel Planner</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/05-amd-yes/openclaw">🦞 OpenClaw Private Assistant</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/05-amd-yes/torch-rechub/">📚 Torch-RecHub Recommender Practice</a> ✅️</td><td></td></tr></tbody></table><blockquote><p>✅ Supported | 🚧 In progress</p></blockquote><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>AMD-YES brings together practical project examples built on AMD GPU and ROCm platform. Whether you want to quickly experience LLM applications, learn computer vision, or dive deep into distributed training, you can find suitable example projects here.</p><p>This module is divided into two stages: First, quickly get started with various applications on a single local GPU, then advance to cluster deployment and distributed training. Each project includes complete code and detailed tutorial guidance.</p><h3 id="amd-yes-learning-path" tabindex="-1">AMD-YES Learning Path <a class="header-anchor" href="#amd-yes-learning-path" aria-label="Permalink to &quot;AMD-YES Learning Path&quot;">​</a></h3><div align="center"><img src="'+i+'" alt="Figure 5.1 AMD-YES project learning path overview" width="95%"></div><h2 id="project-list" tabindex="-1">Project List <a class="header-anchor" href="#project-list" aria-label="Permalink to &quot;Project List&quot;">​</a></h2><h3 id="local-run-single-gpu" tabindex="-1">Local Run (Single GPU) <a class="header-anchor" href="#local-run-single-gpu" aria-label="Permalink to &quot;Local Run (Single GPU)&quot;">​</a></h3><p>Suitable for individual developers to quickly get started – you can do it all with just one AMD GPU!</p><hr><h4 id="🧸-toy-cli-lightweight-llm-terminal-assistant" tabindex="-1">🧸 toy-cli - Lightweight LLM Terminal Assistant <a class="header-anchor" href="#🧸-toy-cli-lightweight-llm-terminal-assistant" aria-label="Permalink to &quot;🧸 toy-cli - Lightweight LLM Terminal Assistant&quot;">​</a></h4><p><a href="https://github.com/KMnO4-zx/toy-cli" target="_blank" rel="noreferrer">toy-cli</a> is a simplified code Agent that provides a minimal command-line interface for calling LLM APIs.</p><ul><li><strong>Target Audience</strong>: Beginners, users wanting to quickly learn API calls</li><li><strong>Difficulty Level</strong>: ⭐</li><li><strong>Estimated Time</strong>: 30 minutes</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/toy-cli">Start Learning toy-cli</a></p><hr><h4 id="🎮-yolov10-wechat-jump" tabindex="-1">🎮 YOLOv10 WeChat Jump <a class="header-anchor" href="#🎮-yolov10-wechat-jump" aria-label="Permalink to &quot;🎮 YOLOv10 WeChat Jump&quot;">​</a></h4><p><a href="https://github.com/KMnO4-zx/wechat-jump" target="_blank" rel="noreferrer">YOLOv10 WeChat Jump</a> is an automated game AI based on YOLOv10 object detection, which automatically recognizes jump targets in real-time and calculates distances accurately.</p><ul><li><strong>Target Audience</strong>: Developers interested in computer vision and game AI</li><li><strong>Difficulty Level</strong>: ⭐⭐</li><li><strong>Estimated Time</strong>: 1 hour</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/wechat-jump">Start Learning WeChat Jump</a></p><hr><h4 id="🎭-chat-huanhuan-palace-language-model" tabindex="-1">🎭 Chat-Huanhuan - Palace Language Model <a class="header-anchor" href="#🎭-chat-huanhuan-palace-language-model" aria-label="Permalink to &quot;🎭 Chat-Huanhuan - Palace Language Model&quot;">​</a></h4><p><a href="https://github.com/KMnO4-zx/huanhuan-chat" target="_blank" rel="noreferrer">Chat-Huanhuan</a> is a LoRA fine-tuned model trained on dialogue excerpts from the TV series, perfectly imitating Huanhuan&#39;s tone and speaking style.</p><ul><li><strong>Target Audience</strong>: Developers wanting to learn model fine-tuning and LoRA techniques</li><li><strong>Difficulty Level</strong>: ⭐⭐</li><li><strong>Estimated Time</strong>: 1.5 hours</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/huanhuan-chat">Start Learning Chat-Huanhuan</a></p><hr><h4 id="✈️-smart-travel-planner" tabindex="-1">✈️ Smart Travel Planner <a class="header-anchor" href="#✈️-smart-travel-planner" aria-label="Permalink to &quot;✈️ Smart Travel Planner&quot;">​</a></h4><p><a href="/hello-rocm/05-amd-yes/hello-agents/">Smart Travel Planner</a> is an intelligent Agent application based on the HelloAgents framework, integrating MCP protocol to call Amap API, running large models locally on AMD GPU.</p><ul><li><strong>Target Audience</strong>: Developers wanting to learn Agent frameworks and MCP protocol</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 2 hours</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/hello-agents/smart-travel-planner/amd395-helloagents-smart-travel-planner">Start Learning Smart Travel Planner</a></p><hr><h4 id="🦞-openclaw-fully-private-local-ai-agent-platform" tabindex="-1">🦞 OpenClaw - Fully Private Local AI Agent Platform <a class="header-anchor" href="#🦞-openclaw-fully-private-local-ai-agent-platform" aria-label="Permalink to &quot;🦞 OpenClaw - Fully Private Local AI Agent Platform&quot;">​</a></h4><p><a href="https://github.com/ValueCell-ai/ClawX" target="_blank" rel="noreferrer">OpenClaw</a> is a unified message processing and AI agent platform. Deploy a large model locally on AMD 395 Max for a fully private personal AI assistant.</p><ul><li><strong>Target Audience</strong>: Developers wanting to learn AI Agent platforms and local privacy deployment</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 1.5 hours</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/openclaw">Start Learning OpenClaw</a></p><hr><h4 id="📚-torch-rechub-recommender-systems-practice" tabindex="-1">📚 Torch-RecHub - Recommender Systems Practice <a class="header-anchor" href="#📚-torch-rechub-recommender-systems-practice" aria-label="Permalink to &quot;📚 Torch-RecHub - Recommender Systems Practice&quot;">​</a></h4><p><a href="https://github.com/datawhalechina/torch-rechub" target="_blank" rel="noreferrer">Torch-RecHub</a> recommender systems practice covers CTR ranking, sequential interest modeling, matching, multi-task learning, experiment tracking, and model export.</p><ul><li><strong>Target Audience</strong>: Developers who want to learn recommender system modeling and training on AMD GPU / ROCm environments</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 3+ hours</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/torch-rechub/">Start Learning Torch-RecHub Recommender Practice</a></p><hr><h3 id="cluster-deployment-multi-gpu" tabindex="-1">Cluster Deployment (Multi-GPU) <a class="header-anchor" href="#cluster-deployment-multi-gpu" aria-label="Permalink to &quot;Cluster Deployment (Multi-GPU)&quot;">​</a></h3><p>Advanced usage – distributed training and deployment!</p><hr><h4 id="🚀-happy-llm-train-large-models-from-scratch" tabindex="-1">🚀 Happy-LLM - Train Large Models from Scratch <a class="header-anchor" href="#🚀-happy-llm-train-large-models-from-scratch" aria-label="Permalink to &quot;🚀 Happy-LLM - Train Large Models from Scratch&quot;">​</a></h4><p><a href="https://github.com/datawhalechina/happy-llm" target="_blank" rel="noreferrer">Happy-LLM</a> provides comprehensive tutorials for distributed multi-machine multi-GPU training, including core principles of large models and hands-on training implementation.</p><ul><li><strong>Target Audience</strong>: Advanced developers wanting to gain deep knowledge of large model training</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 3+ hours</li></ul><p>📖 <a href="/hello-rocm/05-amd-yes/happy-llm/">Start Learning Happy-LLM</a></p><hr><h2 id="environment-requirements" tabindex="-1">Environment Requirements <a class="header-anchor" href="#environment-requirements" aria-label="Permalink to &quot;Environment Requirements&quot;">​</a></h2><h3 id="hardware-requirements" tabindex="-1">Hardware Requirements <a class="header-anchor" href="#hardware-requirements" aria-label="Permalink to &quot;Hardware Requirements&quot;">​</a></h3><ul><li>AMD GPU (ROCm-compatible GPUs, such as RX 7000 series, MI series, etc.)</li><li>Recommended VRAM: 8 GB or more</li></ul><h3 id="software-requirements" tabindex="-1">Software Requirements <a class="header-anchor" href="#software-requirements" aria-label="Permalink to &quot;Software Requirements&quot;">​</a></h3><ul><li>Operating System: Linux (Ubuntu 22.04+) or Windows 11</li><li>ROCm 7.12.0/7.2.0 or higher version</li><li>Python 3.10~3.12</li></ul><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h2><details><summary>Q: How do I verify if my AMD GPU supports ROCm?</summary><p>Please refer to the <a href="https://rocm.docs.amd.com/projects/install-on-linux/en/latest/reference/system-requirements.html" target="_blank" rel="noreferrer">ROCm Official Support List</a> to check supported GPU models.</p></details><details><summary>Q: What is the recommended learning order for these projects?</summary><p>It is recommended to learn in the following order:</p><ol><li>Start with <code>toy-cli</code> first to get familiar with basic LLM API calls</li><li>Choose projects of interest to dive deeper (game AI, dialogue models, Agent applications)</li><li>After completing basic projects, challenge yourself with <code>Happy-LLM</code> for advanced distributed training</li></ol></details><h2 id="reference-resources" tabindex="-1">Reference Resources <a class="header-anchor" href="#reference-resources" aria-label="Permalink to &quot;Reference Resources&quot;">​</a></h2><ul><li><a href="https://github.com/datawhalechina/self-llm" target="_blank" rel="noreferrer">self-llm Complete Tutorial</a></li><li><a href="https://github.com/datawhalechina/hello-agents" target="_blank" rel="noreferrer">HelloAgents AI Agent Framework</a></li><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm Official Documentation</a></li><li><a href="./../">hello-rocm Main Project</a></li></ul><hr><div align="center"><p><strong>Contributions of more project examples are welcome!</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">Submit Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">Submit PR</a></p></div>',64)])])}const g=a(n,[["render",o]]);export{p as __pageData,g as default};
